        # Filter by category
        cat_match = True
        if selected_category_int is not None:
            try:
                if int(b['category']) != selected_category_int:
                    cat_match = False
            except Exception:
                cat_match = False

        # Search filter (title, author, isbn)
        search_match = True
        if search_query:
            search_lower = search_query.lower()
            if search_lower not in b['title'].lower() and search_lower not in b['author'].lower() and search_lower not in b['isbn'].lower():
                search_match = False

        if cat_match and search_match:
            filtered_books.append({
                'book_id': b['book_id'],
                'title': b['title'],
                'author': b['author'],
                'price': b['price'],
                'category': b['category'],
                'isbn': b['isbn']
