def read_reviews():
    reviews = []
    try:
        with open(os.path.join(DATA_DIR, 'reviews.csv'), newline='', encoding='utf-8') as csvfile:
            reader = csv.DictReader(csvfile)
            for row in reader:
                reviews.append({
                    'review_id': row['review_id'],
                    'book_id': row['book_id'],
                    'customer_name': row['customer_name'],
                    'rating': row['rating'],
                    'review_text': row['review_text'],
                    'review_date': row['review_date']
                })
    except Exception:
        pass
    return reviews


def write_reviews(reviews):
    fieldnames = ['review_id', 'book_id', 'customer_name', 'rating', 'review_text', 'review_date']
    try:
        with open(os.path.join(DATA_DIR, 'reviews.csv'), 'w', newline='', encoding='utf-8') as csvfile:
            writer = csv.DictWriter(csvfile, fieldnames=fieldnames)
            writer.writeheader()
            for review in reviews:
                writer.writerow(review)
    except Exception:
        pass


def read_bestsellers():
    bestsellers = []
    try:
        with open(os.path.join(DATA_DIR, 'bestsellers.csv'), newline='', encoding='utf-8') as csvfile:
            reader = csv.DictReader(csvfile)
            for row in reader:
                bestsellers.append({
                    'book_id': row['book_id'],
                    'sales_count': row['sales_count'],
                    'period': row['period']
                })
    except Exception:
        pass
    return bestsellers


